// Process products to get main display data
function processProducts(products) {
  return products.map(product => {
    const variants = product.variants || [];
    const sorted = [...variants].sort((a, b) => a.price - b.price);
    const defaultVar = sorted[0] || { size: '750ml', price: 0, discount: 0 };
    const originalPrice = defaultVar.discount 
      ? Math.round(defaultVar.price * 100 / (100 - defaultVar.discount))
      : defaultVar.price;
    return {
      ...product,
      id: product._id,
      capacity: defaultVar.size,
      price: defaultVar.price,
      originalPrice: originalPrice,
      discountPercent: defaultVar.discount,
      allVariants: variants
    };
  });
}

const PROCESSED_PRODUCTS = processProducts(AM2PM_PRODUCTS);

// Make available globally
if (typeof window !== 'undefined') {
  window.AM2PM_PRODUCTS = AM2PM_PRODUCTS;
  window.PROCESSED_PRODUCTS = PROCESSED_PRODUCTS;
}

// For Node.js
if (typeof module !== 'undefined' && module.exports) {
  module.exports = { AM2PM_PRODUCTS, PROCESSED_PRODUCTS };
}

console.log(`✅ Loaded ${AM2PM_PRODUCTS.length} products from database`);
